const body = $input.first().json.body;
const contactos = body.contactos || [];
const plantillas = [
  '👋🏻Hola! Nos contactamos desde Buenos Aires Logística. 🚚 Tenemos un envío de {empresa} para entregarte.
Queremos avisarte que la entrega se realizará hoy entre las 16:00 y las 22:00 hs.
En caso de que por cuestiones operativas no llegue a completarse dentro de ese rango, la entrega pasará automáticamente al siguiente día hábil entre las 10:30 y las 22:00 hs.
Agradecemos tu comprensión y quedamos atentos ante cualquier consulta 🙌',
  '📦 ¡Hola! Te contactamos desde Buenos Aires Logística.

Queremos informarte que tenemos un envío de {empresa} programado para ser entregado hoy 🚚.

⏰ El horario estimado de entrega es entre las 16:00 y las 22:00 hs.

Si por razones operativas no fuera posible concretar la entrega dentro de ese período, el envío será reprogramado automáticamente para el próximo día hábil entre las 10:30 y las 22:00 hs.

¡Muchas gracias por tu comprensión! 😊 Estamos a disposición para cualquier consulta.',
  '👋 ¡Hola que tal!

Desde Buenos Aires Logística queremos avisarte que tu envío de {empresa} se encuentra en ruta 🚛.

📍 La entrega está prevista para hoy entre las 16:00 y las 22:00 hs.

En caso de surgir alguna demora operativa que impida completar la entrega en ese horario, la misma se realizará el siguiente día hábil dentro de la franja de 10:30 a 22:00 hs.

Gracias por tu paciencia y confianza. 🙌 Ante cualquier duda, estamos para ayudarte.',
  '🚚 ¡Hola!

Te escribimos desde Buenos Aires Logística para informarte que estamos coordinando la entrega de tu envío de {empresa}.

🕓 La visita está programada para realizarse hoy entre las 16:00 y las 22:00 hs.

Si por motivos logísticos la entrega no pudiera efectuarse en ese rango horario, se reagendará automáticamente para el próximo día hábil entre las 10:30 y las 22:00 hs.

✨ Gracias por tu comprensión. Si necesitas asistencia o tienes alguna consulta, no dudes en contactarnos.'
];
const mensajeCustom = (body.mensaje && body.mensaje.trim()) ? body.mensaje.trim() : null;

return contactos.map(c => {
  let tel = String(c.telefono || '').replace(/\D/g, '');
  if (tel.length === 10) tel = '549' + tel;
  const template = mensajeCustom || plantillas[Math.floor(Math.random() * plantillas.length)];
  return { json: { chatId: tel + '@c.us', message: template.replace(/\{empresa\}/gi, c.nombre_empresa || '') } };
});
